import sys
from sys import stdin

def solve():
    MOD = 10**9 + 7
    input_data = stdin.read().split()
    n = int(input_data[0])
    a = list(map(int, input_data[1:n+1]))

    MAX_VAL = max(a) + 1

    # Compute phi using sieve
    phi = list(range(MAX_VAL))
    for i in range(2, MAX_VAL):
        if phi[i] == i:  # i is prime
            for j in range(i, MAX_VAL, i):
                phi[j] -= phi[j] // i

    # Precompute divisors of each a[i]
    divs = [[] for _ in range(n)]
    for i in range(n):
        x = a[i]
        d = 1
        while d * d <= x:
            if x % d == 0:
                divs[i].append(d)
                if d != x // d:
                    divs[i].append(x // d)
            d += 1

    phi_idx = list(range(n+1))
    for i in range(2, n+1):
        if phi_idx[i] == i:
            for j in range(i, n+1, i):
                phi_idx[j] -= phi_idx[j] // i

    ans = 0
    cnt = {}

    for d2 in range(1, n+1):
        cnt.clear()
        for k in range(d2, n+1, d2):
            i = k - 1  # 0-indexed
            for d1 in divs[i]:
                cnt[d1] = cnt.get(d1, 0) + 1
        ph2 = phi_idx[d2]
        for d1, c in cnt.items():
            ans = (ans + phi[d1] * ph2 % MOD * c % MOD * c) % MOD

    print(ans)

solve()
